import{_ as t,o as s,c as r,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"106. Undergraduate Employment Models","description":"","frontmatter":{"title":"106. Undergraduate Employment Models","eba":"Nurses and Midwives 2024-2028","topics":["preliminary","definitions","staffing","education-pd"]},"headers":[],"relativePath":"ebas/nurses-midwives/safe-patient-care/106-undergraduate-employment-models.md","filePath":"ebas/nurses-midwives/safe-patient-care/106-undergraduate-employment-models.md"}'),n={name:"ebas/nurses-midwives/safe-patient-care/106-undergraduate-employment-models.md"};function a(i,e,d,p,l,m){return s(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="_106-undergraduate-employment-models" tabindex="-1">106. Undergraduate Employment Models <a class="header-anchor" href="#_106-undergraduate-employment-models" aria-label="Permalink to &quot;106. Undergraduate Employment Models&quot;">​</a></h1><p>RUSONs/RUSOMs/RENS</p><p>Note: With effect from 1 July 2024.</p><p><strong>106.1</strong> Definition</p><p><strong>(a)</strong> A Registered Undergraduate Student of Nursing or RUSON for the purposes of this clause is a person currently enrolled at a University to undertake undergraduate nursing study, who is registered with AHPRA as a student nurse, and who at commencement, has successfully completed not less than 12 months of their course.</p><p><strong>(b)</strong> A Registered Undergraduate Student of Midwifery or RUSOM for the purposes of this clause is a person currently enrolled at a University to undertake undergraduate midwifery study, who is registered with APHRA as a student midwife, and who at commencement, has successfully completed not less than 12 months of their course.</p><p><strong>(c)</strong> A Registered Enrolled Nurse Student or RENS for the purposes of this clause is a person currently enrolled to undertake Diploma nursing study, who is registered with AHPRA as a student nurse.</p><p><strong>106.2</strong> Employment as RUSONs/RUSOMs/RENS</p><p><strong>(a)</strong> RUSON/RUSOM/RENS will be employed on a fixed term basis or engaged on a casual basis.</p><p><strong>(b)</strong> RUSONs/RUSOMs/RENS will be delegated activities and aspects of care by a Registered Nurse/Registered Midwife and supervised in providing the delegated activity by the Registered Nurse/Registered Midwife. The</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 222</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers</p><p>RUSON/RUSOM/RENS must at all times work under the delegation and supervision of the Registered Nurse/Registered Midwife in accordance with a documented position description that is appropriate having regard to the level of education completed.</p><p><strong>(c)</strong> RUSONs/RUSOMs/RENS will not be given sole patient allocation but instead work with one or more nurses/midwives in the provision of care to a group of patients.</p><p><strong>106.3</strong> Termination of Employment</p><p><strong>(a)</strong> Employment will conclude:</p><p><strong>(i)</strong> from when the Employee terminates their employment;</p><p><strong>(ii)</strong> from when the Employer terminates the employment in accordance with this Agreement.</p><p><strong>(iii)</strong> on being granted registration as a Registered Nurse, Registered Midwife, or Enrolled Nurse unless the Employee, Employer and the ANMF agree in writing to continue the employment for a short period of time to cover the period between registration and commencement of a graduate or similar program;</p><p><strong>(iv)</strong> when the Employee withdraws, defers from or fails their course of education; or</p><p><strong>(v)</strong> in the case of a casual, in accordance with <a href="/eba/ebas/doctors-in-training/doctor-employment/19-casual-employment.html">clause 19</a> (Casual Employment).</p><p><strong>106.4</strong> Rate of pay for RUSONs/RUSOMs/RENS</p><p>A RUSON/RUSOM/REN will be paid on the following basis:</p><p>RUSON/RUSOM /RENS Percentage of Grade 2 Year 1 rate of pay set out in Part 1 of <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a></p><p>RUSON/RUSOM/RENS 81.5%</p><p><strong>106.5</strong> Other terms and conditions for RUSONs/RUSOMs/RENS</p><p>All other terms and conditions of employment will be those applying to a Registered Nurse/Registered Midwife/Enrolled Nurse under this Agreement except where this clause explicitly says otherwise.</p><p><strong>106.6</strong> Continuity of service</p><p>Continuity of Service as a Registered Nurse/Registered Midwife/Enrolled Nurse will include any period of service in the program, provided any gap between employment as a student and commencement of employment as a Registered Nurse/Registered Midwife/Enrolled Nurse is less than 12 months.</p><p><strong>106.7</strong> Notification to ANMF</p><p>The Employer will notify the ANMF, on request, of:</p><p><strong>(a)</strong> the participating wards/units;</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 223</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers</p><p><strong>(b)</strong> EFT quantum and fraction of each undergraduate student category operating within the ward; and</p><p><strong>(c)</strong> the RUSON/RUSOM/RENS Position Description, the Core activity list, and the Exclusion List.</p><p>Plain language terms: undergrad model, student employment.</p>',37)])])}const h=t(n,[["render",a]]);export{g as __pageData,h as default};
